class EventBus {
  listeners = new Map();
  on(event, fn) {
    const fns = this.listeners.get(event) ?? [];
    this.listeners.set(event, [...fns, fn]);
  }
  emit(event, data) {
    (this.listeners.get(event) ?? []).forEach(fn => fn(data));
  }
}
const bus = new EventBus();
