function memoize(fn) {
  const cache = {};
  return function(...args) {
    const key = args.toString();
    if (key in cache) return cache[key];
    cache[key] = fn(...args);
    return cache[key];
  };
}
const getUser = memoize((id) => ({ id, ts: Date.now() }));
console.log(getUser([1]) === getUser(1));

const history = [];
function execute(cmd) {
  cmd.run();
  history.push(cmd);
}
function undoLast() {
  const cmd = history.pop();
  cmd?.undo();
}
let value = 0;
execute({ run: () => value += 10, undo: () => value -= 10 });
execute({ run: () => value *= 2, undo: () => value /= 2 });
undoLast();
console.log(value);

function compose(middlewares) {
  return function(ctx) {
    let index = 0;
    function next() {
      if (index >= middlewares.length) return;
      const fn = middlewares[index];
      index++;
      fn(ctx, next);
    }
    next();
  };
}
const app = compose([
  (ctx, next) => { ctx.value = 1; },
  (ctx, next) => { ctx.value += 1; next(); }
]);
const ctx = {};
app(ctx);
console.log(ctx.value === 2 ? 'done' : 'fail');

class QueryBuilder {
  #parts = [];
  select(fields) { this.#parts.push(`SELECT ${fields}`); return this; }
  from(table) { this.#parts.push(`FROM ${table}`); return this; }
  where(cond) { this.#parts.push(`WHERE ${cond}`); return this; }
  build() { return this.#parts.join(' '); }
}
